INSERT INTO t_p67171637_yug_transfer_prize_l.bot_daily_posts (photo_url, greeting, description) VALUES
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/d3fdfb54-8c49-41e8-9c4d-ebb1db802b2a.jpg', '🚕 Утренний рейс? Будем у подъезда без опозданий!', 'Бронируйте авто заранее — встретим точно ко времени, даже в 4 утра.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/22e0e0b9-faf3-46a4-8183-f531cb0c61c6.jpg', '🚕 Комфорт в каждой детали!', 'Кожаный салон, климат-контроль, бутылочка воды и зарядка для телефона.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/2befae09-4ec8-457b-9bbe-a5085e235cd1.jpg', '🚕 Большая семья? Места хватит всем!', 'Минивэны на 6–8 пассажиров с просторным багажником. Едем все вместе!'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/45fee257-0dfb-4469-bda1-40f8da0c0d1e.jpg', '🚕 Свадебный кортеж — украсим праздник!', 'Авто с лентами, шарами и опытным водителем. Подъезд минута в минуту.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/af474085-9bf9-48ce-82d1-ad0165ec83a9.jpg', '🚕 Бизнес-класс для деловых поездок', 'Mercedes E-class, Toyota Camry — встретим партнёров на высоком уровне.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/400c6f03-3b70-46aa-8154-857929f7f242.jpg', '🚕 Туристам — экскурсии с водителем!', 'Покажем главные достопримечательности побережья. Маршрут — по вашему желанию.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/3f776fde-4af2-4080-9744-1f6ab0e1c7a5.jpg', '🚕 Серпантин — наша стихия!', 'Опытные водители знают каждый поворот горных дорог Кавказа.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/0cc4a341-7274-41aa-a948-fce01112130b.jpg', '🚕 Только проверенные водители!', 'Стаж от 5 лет, вежливое общение, помощь с багажом — всегда.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/e62f0de5-5b80-4a93-9464-8a28f6b8e46e.jpg', '🚕 Ночные рейсы — без переплат!', 'Работаем 24/7 по фиксированному тарифу. Ночной коэффициент — не про нас.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/baed04df-0496-42ab-af80-90e61b311c27.jpg', '🚕 Детское кресло — бесплатно!', 'Для малышей и школьников. Безопасность маленьких пассажиров — приоритет.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/642fddb9-e81d-4607-a39c-1765553e229f.jpg', '🚕 Компанией — выгоднее, чем поездом!', 'Сравните: 6 человек × билет vs 1 микроавтобус. Считаем — экономия очевидна.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/bbd0c485-9626-4dd3-bf58-8b22d34ece86.jpg', '🚕 Закат у моря — лучшее время для поездки!', 'Доставим к набережной, ресторану или смотровой площадке.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/796b6be1-1f4f-4eee-9a9f-936443c9d9a4.jpg', '🚕 Заказ за минуту — через бот или звонок', 'Без приложений и регистраций. Просто напишите — и водитель уже едет.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/58d9fc58-a139-4e87-ac2b-20487425f5f3.jpg', '🚕 Школа, секции, кружки — отвезём ребёнка!', 'Постоянные рейсы для школьников. Один проверенный водитель, родители спокойны.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/8f80f73a-c7da-4ad2-b6fc-3652a7449939.jpg', '🚕 Красная Поляна, Газпром, Роза Хутор', 'Доставим на горнолыжные курорты с лыжами, бордами и хорошим настроением.');